// Update allows overriding fields `UPDATE` values. See the UpstreamTargetCreateBulk.OnConflict
// documentation for more info.
func (u *UpstreamTargetUpsertBulk) Update(set func(*UpstreamTargetUpsert)) *UpstreamTargetUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&UpstreamTargetUpsert{UpdateSet: update})
	}))
	return u
}

